import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_versions(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_versions(baseline)
a = get_versions(after)

changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k, bv, av))

if changes:
    print('CHANGES:')
    for (proj, fw, pkg), bv, av in changes:
        print(f'  {proj} ({fw}) {pkg}: {bv} -> {av}')
else:
    print('NO CHANGES - version neutral conversion')
"

